#include <bits/stdc++.h>

using namespace std;
#define int long long
int32_t main()
{
    ios_base::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    int t;
    cin >> t;
    while (t--)
    {
        int adj[6][2];
        adj[1][0] = 1;
        adj[1][1] = 2;
        adj[2][0] = 3;
        adj[2][1] = 2;
        adj[3][0] = 4;
        adj[3][1] = 2;
        adj[4][0] = 5;
        adj[4][1] = 2;
        adj[5][0] = 1;
        adj[5][1] = 2;
        string s;
        cin >> s;
        int curr = 1, n = s.size();

        for (int i = 0; i < n; i++)
            curr = adj[curr][s[i] - '0'];

        if (curr == 5)
            cout << "YES\n";
        else
            cout << "NO\n";
    }
    return 0;
}
